        content: [
          { question: '1. 实现一个完整的客户流失预测系统，使用多种算法比较并选择最佳模型。', initialCode: '# 客户流失预测系统\nimport math\nimport random\n\nrandom.seed(100)\n\n# 模拟客户数据: (使用月数, 月消费, 客服次数, 是否流失 1=流失)\ncustomers = [\n    (12, 200, 5, 0), (24, 350, 2, 0), (6, 50, 15, 1), (36, 500, 1, 0),\n    (3, 30, 20, 1), (18, 280, 3, 0), (8, 80, 12, 1), (48, 600, 0, 0),\n    (5, 40, 18, 1), (30, 420, 2, 0), (4, 35, 16, 1), (36, 550, 1, 0),\n    (9, 90, 10, 1), (20, 320, 4, 0), (7, 60, 14, 1), (40, 580, 1, 0),\n    (10, 100, 8, 1), (28, 400, 3, 0), (5, 45, 17, 1), (32, 480, 2, 0),\n    (15, 250, 5, 0), (6, 55, 13, 1), (22, 360, 3, 0), (8, 75, 11, 1),\n    (36, 520, 1, 0), (4, 38, 19, 1), (18, 290, 4, 0), (10, 95, 9, 1),\n    (25, 380, 2, 0), (7, 65, 12, 1), (30, 450, 2, 0), (5, 42, 18, 1),\n    (20, 330, 3, 0), (9, 85, 10, 1), (35, 510, 1, 0), (6, 52, 14, 1),\n    (22, 370, 3, 0), (8, 72, 11, 1), (28, 410, 2, 0), (5, 40, 16, 1)\n]\n\nprint(\"=\" * 60)\nprint(\"          客户流失预测系统\")\nprint(\"=\" * 60)\n\n# 数据统计\nchurned = [c for c in customers if c[3] == 1]\nretained = [c for c in customers if c[3] == 0]\nprint(\"\\n【数据概况】\")\nprint(\"总客户数: \" + str(len(customers)))\nprint(\"流失客户: \" + str(len(churned)) + \" (\" + str(round(len(churned) / len(customers) * 100, 1)) + \"%)\")\nprint(\"留存客户: \" + str(len(retained)) + \" (\" + str(round(len(retained) / len(customers) * 100, 1)) + \"%)\")\n\nprint(\"\\n【流失客户特征】\")\nprint(\"平均使用月数: \" + str(round(sum(c[0] for c in churned) / len(churned), 1)) + \" 个月\")\nprint(\"平均月消费: \" + str(round(sum(c[1] for c in churned) / len(churned), 1)) + \" 元\")\nprint(\"平均客服次数: \" + str(round(sum(c[2] for c in churned) / len(churned), 1)) + \" 次\")\n\nprint(\"\\n【留存客户特征】\")\nprint(\"平均使用月数: \" + str(round(sum(c[0] for c in retained) / len(retained), 1)) + \" 个月\")\nprint(\"平均月消费: \" + str(round(sum(c[1] for c in retained) / len(retained), 1)) + \" 元\")\nprint(\"平均客服次数: \" + str(round(sum(c[2] for c in retained) / len(retained), 1)) + \" 次\")\n\n# 训练朴素贝叶斯\nchurn_feats = [(c[0], c[1], c[2]) for c in churned]\nretain_feats = [(c[0], c[1], c[2]) for c in retained]\n\ndef feat_stats(feats):\n    n = len(feats)\n    num_feats = len(feats[0])\n    summaries = []\n    for j in range(num_feats):\n        col = [row[j] for row in feats]\n        mean_val = sum(col) / n\n        var_val = sum((x - mean_val) ** 2 for x in col) / n\n        summaries.append((mean_val, var_val))\n    return summaries\n\nchurn_stats = feat_stats(churn_feats)\nretain_stats = feat_stats(retain_feats)\n\nchurn_prior = len(churned) / len(customers)\nretain_prior = len(retained) / len(customers)\n\ndef gaussian_prob(x, mean, var):\n    if var == 0:\n        return 1.0 if x == mean else 0.001\n    exponent = -((x - mean) ** 2) / (2 * var)\n    return math.exp(exponent) / math.sqrt(2 * math.pi * var)\n\ndef predict_churn(features):\n    churn_score = math.log(churn_prior)\n    for j in range(len(features)):\n        mean_val, var_val = churn_stats[j]\n        prob = gaussian_prob(features[j], mean_val, var_val)\n        churn_score += math.log(max(prob, 1e-10))\n    retain_score = math.log(retain_prior)\n    for j in range(len(features)):\n        mean_val, var_val = retain_stats[j]\n        prob = gaussian_prob(features[j], mean_val, var_val)\n        retain_score += math.log(max(prob, 1e-10))\n    return 1 if churn_score > retain_score else 0\n\n# 评估模型\nprint(\"\\n【模型预测结果】\")\ncorrect = 0\nfor c in customers:\n    pred = predict_churn((c[0], c[1], c[2]))\n    status = \"✓\" if pred == c[3] else \"✗\"\n    result = \"流失\" if pred == 1 else \"留存\"\n    actual = \"流失\" if c[3] == 1 else \"留存\"\n    print(status + \" 客户(月数=\" + str(c[0]) + \",消费=\" + str(c[1]) + \",客服=\" + str(c[2]) + \") 预测:\" + result + \" 实际:\" + actual)\n    if pred == c[3]:\n        correct += 1\n\nprint(\"\\n【模型评估】\")\nprint(\"训练准确率: \" + str(correct) + \"/\" + str(len(customers)) + \" = \" + str(round(correct / len(customers) * 100, 1)) + \"%\")\n\n# 新客户预测\nprint(\"\\n【新客户风险预测】\")\nnew_customers = [\n    (4, 45, 18),\n    (10, 150, 8),\n    (24, 380, 3),\n    (36, 520, 1)\n]\nfor nc in new_customers:\n    pred = predict_churn(nc)\n    risk = \"高风险(可能流失)\" if pred == 1 else \"低风险(预计留存)\"\n    print(\"新客户(月数=\" + str(nc[0]) + \",消费=\" + str(nc[1]) + \",客服=\" + str(nc[2]) + \") -> \" + risk)\n\nprint(\"\\n\" + \"=\" * 60)' },
          { question: '2. 实现一个手写数字识别的简化版本，使用K近邻和距离加权投票。', initialCode: '# 简化数字识别系统\nimport math\nimport random\n\nrandom.seed(2024)\n\n# 简化数字特征: (笔画数, 闭合区域数, 水平线条数, 垂直线条数, 标签)\ndigits = [\n    (1, 1, 1, 2, 0), (1, 1, 0, 2, 0), (1, 1, 1, 1, 0),\n    (2, 0, 2, 1, 1), (2, 0, 1, 1, 1), (2, 0, 2, 2, 1),\n    (3, 0, 2, 2, 2), (3, 0, 3, 1, 2), (3, 0, 2, 1, 2),\n    (2, 1, 1, 2, 3), (2, 1, 2, 2, 3), (2, 1, 2, 1, 3),\n    (2, 1, 1, 3, 4), (2, 1, 2, 3, 4), (2, 1, 1, 2, 4),\n    (2, 1, 2, 2, 5), (2, 1, 2, 1, 5), (3, 1, 2, 2, 5),\n    (2, 1, 2, 3, 6), (3, 1, 2, 3, 6), (2, 1, 3, 2, 6),\n    (2, 0, 2, 2, 7), (2, 0, 2, 1, 7), (3, 0, 2, 2, 7),\n    (2, 2, 2, 3, 8), (2, 2, 3, 2, 8), (3, 2, 2, 3, 8),\n    (2, 1, 2, 2, 9), (2, 1, 2, 3, 9), (2, 1, 3, 2, 9)\n]\n\nprint(\"=\" * 60)\nprint(\"        简化数字识别系统 (K近邻)\")\nprint(\"=\" * 60)\n\nk = 5\n\ndef dist_feat(a, b):\n    d = 0\n    for i in range(len(a)):\n        d += (a[i] - b[i]) ** 2\n    return math.sqrt(d)\n\ndef knn_weighted(test_feat):\n    distances = []\n    for d in digits:\n        feat = (d[0], d[1], d[2], d[3])\n        dist_val = dist_feat(feat, test_feat)\n        distances.append((dist_val, d[4]))\n    distances.sort(key=lambda x: x[0])\n    \n    neighbors = distances[:k]\n    votes = {}\n    for nb in neighbors:\n        weight = 1.0 / (nb[0] + 0.001)\n        label = nb[1]\n        votes[label] = votes.get(label, 0) + weight\n    return max(votes, key=votes.get), neighbors\n\n# 数据统计\nprint(\"\\n【训练数据统计】\")\nprint(\"总样本数: \" + str(len(digits)))\nlabel_counts = {}\nfor d in digits:\n    label_counts[d[4]] = label_counts.get(d[4], 0) + 1\nfor lbl in sorted(label_counts):\n    print(\"数字\" + str(lbl) + \": \" + str(label_counts[lbl]) + \" 个样本\")\n\n# 训练集评估\nprint(\"\\n【训练集预测结果 (留一法验证)】\")\ncorrect = 0\nfor idx in range(len(digits)):\n    test_feat = (digits[idx][0], digits[idx][1], digits[idx][2], digits[idx][3])\n    actual_label = digits[idx][4]\n    \n    # 临时移除当前样本\n    temp_digits = digits[:idx] + digits[idx + 1:]\n    distances = []\n    for d in temp_digits:\n        feat = (d[0], d[1], d[2], d[3])\n        dist_val = dist_feat(feat, test_feat)\n        distances.append((dist_val, d[4]))\n    distances.sort(key=lambda x: x[0])\n    neighbors = distances[:k]\n    votes = {}\n    for nb in neighbors:\n        weight = 1.0 / (nb[0] + 0.001)\n        label = nb[1]\n        votes[label] = votes.get(label, 0) + weight\n    pred = max(votes, key=votes.get)\n    \n    status = \"✓\" if pred == actual_label else \"✗\"\n    print(status + \" 样本\" + str(idx + 1).rjust(2) + \": 真实=\" + str(actual_label) + \", 预测=\" + str(pred))\n    if pred == actual_label:\n        correct += 1\n\nprint(\"\\n【模型性能】\")\nprint(\"留一法验证准确率: \" + str(correct) + \"/\" + str(len(digits)) + \" = \" + str(round(correct / len(digits) * 100, 1)) + \"%\")\n\n# 新样本预测\nprint(\"\\n【新样本识别测试】\")\ntest_samples = [\n    (1, 1, 1, 2, \"类似0\"),\n    (2, 0, 2, 1, \"类似1\"),\n    (3, 0, 2, 2, \"类似2\"),\n    (2, 1, 2, 2, \"类似3或5\"),\n    (2, 2, 3, 3, \"类似8\")\n]\nfor sample in test_samples:\n    feat = (sample[0], sample[1], sample[2], sample[3])\n    pred, neighbors = knn_weighted(feat)\n    print(\"特征\" + str(feat) + \" (\" + sample[4] + \") -> 识别为数字 \" + str(pred))\n    print(\"  最近\" + str(k) + \"个邻居距离: \" + str([round(n[0], 2) for n in neighbors]))\n    print(\"  邻居标签: \" + str([n[1] for n in neighbors]))\n\nprint(\"\\n\" + \"=\" * 60)' }
        ]
