            initialCode: '# 模拟SQL: SELECT * FROM employees WHERE department = "IT" AND salary > 8000\nemployees = [\n    {"id": 1, "name": "张三", "department": "IT", "salary": 8000, "age": 28},\n    {"id": 2, "name": "李四", "department": "销售", "salary": 7500, "age": 32},\n    {"id": 3, "name": "王五", "department": "IT", "salary": 12000, "age": 35},\n    {"id": 4, "name": "赵六", "department": "财务", "salary": 9000, "age": 40},\n    {"id": 5, "name": "钱七", "department": "IT", "salary": 15000, "age": 45}\n]\n\ndef where_query(table, conditions):\n    result = []\n    for row in table:\n        match = True\n        for cond in conditions:\n            key, op, value = cond\n            if op == "=" and row[key] != value:\n                match = False\n            elif op == ">" and not (row[key] > value):\n                match = False\n            elif op == "<" and not (row[key] < value):\n                match = False\n            elif op == ">=" and not (row[key] >= value):\n                match = False\n            elif op == "<=" and not (row[key] <= value):\n                match = False\n            elif op == "!=" and row[key] == value:\n                match = False\n            if not match:\n                break\n        if match:\n            result.append(row)\n    return result\n\nprint("=== WHERE department = IT AND salary > 8000 ===")\nresult = where_query(employees, [("department", "=", "IT"), ("salary", ">", 8000)])\nfor row in result:\n    print(row["name"] + ", 部门: " + row["department"] + ", 工资: " + str(row["salary"]))'
