            initialCode: '# 综合SQL查询引擎: SELECT col1, col2 FROM table WHERE cond ORDER BY col DESC LIMIT n\nimport math\n\norders = [\n    {"order_id": 1001, "customer": "客户A", "amount": 2500, "status": "已完成", "year": 2023},\n    {"order_id": 1002, "customer": "客户B", "amount": 1800, "status": "处理中", "year": 2023},\n    {"order_id": 1003, "customer": "客户A", "amount": 5200, "status": "已完成", "year": 2024},\n    {"order_id": 1004, "customer": "客户C", "amount": 800, "status": "已取消", "year": 2023},\n    {"order_id": 1005, "customer": "客户B", "amount": 3200, "status": "已完成", "year": 2024},\n    {"order_id": 1006, "customer": "客户D", "amount": 4500, "status": "处理中", "year": 2024},\n    {"order_id": 1007, "customer": "客户A", "amount": 1500, "status": "已完成", "year": 2023}\n]\n\ndef query_engine(table, columns, where_conditions=[], order_by=None, ascending=True, limit=None):\n    result = []\n    for row in table:\n        if where_conditions:\n            all_match = True\n            for cond_group in where_conditions:\n                if isinstance(cond_group, list):\n                    any_match = False\n                    for cond in cond_group:\n                        key, op, value = cond\n                        if check_condition(row[key], op, value):\n                            any_match = True\n                            break\n                    if not any_match:\n                        all_match = False\n                        break\n                else:\n                    key, op, value = cond_group\n                    if not check_condition(row[key], op, value):\n                        all_match = False\n                        break\n            if not all_match:\n                continue\n        result.append(row)\n    if order_by:\n        result.sort(key=lambda x: x[order_by], reverse=not ascending)\n    if limit:\n        result = result[:limit]\n    if columns and columns[0] != "*":\n        filtered = []\n        for row in result:\n            new_row = {}\n            for col in columns:\n                new_row[col] = row[col]\n            filtered.append(new_row)\n        return filtered\n    return result\n\ndef check_condition(value, op, target):\n    if op == "=":\n        return value == target\n    elif op == "!=":\n        return value != target\n    elif op == ">":\n        return value > target\n    elif op == "<":\n        return value < target\n    elif op == ">=":\n        return value >= target\n    elif op == "<=":\n        return value <= target\n    return False\n\nprint("=" * 60)\nprint("【综合SQL查询引擎 - 订单数据分析】")\nprint("=" * 60)\n\nprint("\\n1. 查询2024年金额>2000的订单，按金额降序取前3名:")\nprint("   SELECT order_id, customer, amount FROM orders WHERE year=2024 AND amount>2000 ORDER BY amount DESC LIMIT 3")\nresult1 = query_engine(orders, ["order_id", "customer", "amount"],\n                       [("year", "=", 2024), ("amount", ">", 2000)],\n                       order_by="amount", ascending=False, limit=3)\nfor r in result1:\n    print("   订单" + str(r["order_id"]) + " - " + r["customer"] + " - 金额:" + str(r["amount"]))\n\nprint("\\n2. 查询已完成或已取消的所有订单:")\nprint("   SELECT * FROM orders WHERE status=\"已完成\" OR status=\"已取消\"")\nresult2 = query_engine(orders, ["order_id", "customer", "status", "amount"],\n                       [[("status", "=", "已完成"), ("status", "=", "已取消")]])\nfor r in result2:\n    print("   " + str(r["order_id"]) + " - " + r["customer"] + " - " + r["status"] + " - " + str(r["amount"]))\n\ntotal_amount = sum(r["amount"] for r in result2)\nprint("   此类订单总金额: " + str(total_amount))'
