            initialCode: '# 模拟SQL CASE WHEN + 窗口函数RANK() OVER (PARTITION BY dept ORDER BY salary DESC)\nimport math\n\nemployees = [\n    {"id": 1, "name": "张三", "department": "IT", "salary": 8000},\n    {"id": 2, "name": "李四", "department": "销售", "salary": 7500},\n    {"id": 3, "name": "王五", "department": "IT", "salary": 12000},\n    {"id": 4, "name": "赵六", "department": "财务", "salary": 9000},\n    {"id": 5, "name": "孙七", "department": "销售", "salary": 8500},\n    {"id": 6, "name": "周八", "department": "IT", "salary": 15000},\n    {"id": 7, "name": "吴九", "department": "财务", "salary": 9500},\n    {"id": 8, "name": "郑十", "department": "销售", "salary": 11000}\n]\n\ndef case_when_salary(salary):\n    if salary >= 12000:\n        return "高薪"\n    elif salary >= 9000:\n        return "中等"\n    elif salary >= 7000:\n        return "普通"\n    else:\n        return "较低"\n\ndef rank_within_group(table, group_col, order_col, ascending=False):\n    groups = {}\n    for row in table:\n        key = row[group_col]\n        if key not in groups:\n            groups[key] = []\n        groups[key].append(row)\n    result = []\n    for key, members in groups.items():\n        sorted_members = sorted(members, key=lambda x: x[order_col], reverse=not ascending)\n        for rank, m in enumerate(sorted_members):\n            entry = {}\n            entry.update(m)\n            entry["rank"] = rank + 1\n            entry["salary_level"] = case_when_salary(m[order_col])\n            result.append(entry)\n    result.sort(key=lambda x: (x[group_col], x["rank"]))\n    return result\n\nprint("=" * 60)\nprint("【CASE WHEN分级 + 分组排名分析】")\nprint("=" * 60)\nranked = rank_within_group(employees, "department", "salary")\nprint("部门 | 排名 | 姓名 | 工资 | 等级")\nprint("-" * 60)\nfor r in ranked:\n    print(r["department"].ljust(6) + " | " + str(r["rank"]).rjust(4) + " | " +\n          r["name"].ljust(6) + " | " + str(r["salary"]).rjust(5) + " | " + r["salary_level"])\n\nprint("\\n【薪资等级分布】")\nlevels = {}\nfor emp in employees:\n    lvl = case_when_salary(emp["salary"])\n    levels[lvl] = levels.get(lvl, 0) + 1\nfor lvl in ["高薪", "中等", "普通", "较低"]:\n    if lvl in levels:\n        print("  " + lvl + ": " + str(levels[lvl]) + " 人 (" +\n              str(round(levels[lvl] / len(employees) * 100, 1)) + "%)")\n\nprint("\\n【各部门第一名】")\nfor r in ranked:\n    if r["rank"] == 1:\n        print("  " + r["department"] + "部门冠军: " + r["name"] + " - " + str(r["salary"]))'
